import sys

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def inorderTraversal(self, root: TreeNode) -> list[int]:
        result = []
        stack = []
        current = root
        while True:
            if current is not None:
                stack.append(current)
                current = current.left
            elif stack:
                current = stack.pop()
                result.append(current.val)
                current = current.right
            else:
                break
        return result

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        root = None
        nodes = []
        for _ in range(n):
            val = int(next(it))
            node = TreeNode(val) if val != -1 else None
            nodes.append(node)
        for i in range(n):
            node = nodes[i]
            if node is not None:
                left_idx = i * 2 + 1
                right_idx = i * 2 + 2
                if left_idx < n:
                    node.left = nodes[left_idx]
                if right_idx < n:
                    node.right = nodes[right_idx]
        root = nodes[0]
        sol = Solution()
        ans = sol.inorderTraversal(root)
        print(" ".join(map(str, ans)))
    except StopIteration:
        sys.exit(0)

